exercises.solution:
class Account
  attr_reader :balance
  def initialize(start)
    @balance = start
  end
  def deposit(n)
    @balance += n
    @balance
  end
  def withdraw(n)
    return false if n > @balance
    @balance -= n
    @balance
  end
end

