exercises.solution:
class Buffer
  def initialize
    @items = []
  end
  def add(x)
    @items.push(x)
    x
  end
  def take
    raise "buffer empty" if @items.empty?
    @items.shift
  end
  def empty?
    @items.empty?
  end
end

